import{_ as t,a,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as i,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"เพิ่ม S3 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/upload/s3.md","filePath":"th-TH/upload/s3.md","lastUpdated":1781962217000}'),c={name:"th-TH/upload/s3.md"};function r(p,e,h,u,m,b){return i(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="เพิ่ม-s3-channel" tabindex="-1">เพิ่ม S3 Channel <a class="header-anchor" href="#เพิ่ม-s3-channel" aria-label="Permalink to &quot;เพิ่ม S3 Channel&quot;">​</a></h1><h2 id="เหมาะกับกรณีไหน" tabindex="-1">เหมาะกับกรณีไหน <a class="header-anchor" href="#เหมาะกับกรณีไหน" aria-label="Permalink to &quot;เหมาะกับกรณีไหน&quot;">​</a></h2><p>ใช้ S3 channel เมื่อ:</p><ul><li>ต้องการเชื่อมต่อ object storage service ที่รองรับ S3 เช่น Cloudflare R2, Backblaze B2, MinIO, AWS S3 หรือ provider อื่นที่ compatible</li><li>ชอบรูปแบบการตั้งค่า S3 มาตรฐาน: <code>Endpoint</code>, Access Key และ Secret Key</li><li>ไม่ต้องการใช้ native Cloudflare R2 binding channel หรือ storage provider ของคุณไม่ใช่ Cloudflare R2</li></ul><h2 id="สิ่งที่ต้องเตรียมก่อนเริ่ม" tabindex="-1">สิ่งที่ต้องเตรียมก่อนเริ่ม <a class="header-anchor" href="#สิ่งที่ต้องเตรียมก่อนเริ่ม" aria-label="Permalink to &quot;สิ่งที่ต้องเตรียมก่อนเริ่ม&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>S3 API endpoint ของ object storage service</td></tr><tr><td>Bucket name</td><td>Bucket ที่จะใช้เก็บ files</td></tr><tr><td>Region</td><td>Storage region สำหรับ Cloudflare R2 มักเป็น <code>auto</code></td></tr><tr><td>Access Key ID</td><td>S3 access key ID</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key</td></tr><tr><td>CDN domain</td><td>Custom domain สำหรับ file access แบบ optional</td></tr></tbody></table><p>ตัวอย่าง Cloudflare R2 ผ่าน S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="เพิ่มได้จากที่ไหน" tabindex="-1">เพิ่มได้จากที่ไหน <a class="header-anchor" href="#เพิ่มได้จากที่ไหน" aria-label="Permalink to &quot;เพิ่มได้จากที่ไหน&quot;">​</a></h2><ol><li>เปิด System Settings</li><li>ไปที่ Upload Settings</li><li>คลิก Add Channel ที่มุมขวาบน</li><li>เลือก <code>S3</code></li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>ใช้ทำอะไร</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>ชื่อที่จำง่ายสำหรับ S3 channel เช่น <code>s3test</code> หรือ <code>R2-S3</code></td><td>Yes</td></tr><tr><td>Enable channel</td><td>ควบคุมว่า channel นี้จะเข้าร่วม upload selection หรือไม่</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>Full S3 service endpoint รวม <code>https://</code></td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>Optional เมื่อใส่แล้ว generated file links จะ prefer domain นี้</td><td>No</td></tr><tr><td>Bucket name</td><td>Bucket name เช่น <code>s3test</code> หรือ <code>img-r2</code></td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region สำหรับ Cloudflare R2 มักเป็น <code>auto</code></td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key</td><td>Yes</td></tr><tr><td>Path-style access</td><td>Compatibility switch ค่าเริ่มต้น off บาง MinIO, OpenList หรือ self-hosted S3 service อาจต้องใช้</td><td>No</td></tr><tr><td>Quota limit</td><td>ควบคุมว่า S3 channel นี้เข้าร่วม upload selection ตาม capacity หรือไม่</td><td>No</td></tr><tr><td>Capacity limit</td><td>Required หลังเปิด quota limit เช่น <code>10 GB</code></td><td>Required เมื่อเปิด quota limit</td></tr><tr><td>Threshold</td><td>หยุดเขียนเมื่อ usage ถึง percentage นี้ เช่น <code>90%</code></td><td>Required เมื่อเปิด quota limit</td></tr><tr><td>Remark</td><td>หมายเหตุสำหรับดูแลเอง</td><td>No</td></tr></tbody></table><h2 id="สร้าง-cloudflare-r2-s3-api-keys" tabindex="-1">สร้าง Cloudflare R2 S3 API Keys <a class="header-anchor" href="#สร้าง-cloudflare-r2-s3-api-keys" aria-label="Permalink to &quot;สร้าง Cloudflare R2 S3 API Keys&quot;">​</a></h2><ol><li>เปิด Cloudflare Dashboard</li><li>ไปที่ <code>R2 Object Storage</code></li><li>หา <code>Manage R2 API Tokens</code> หรือ entry สำหรับจัดการ API token</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>สร้าง R2 API token ที่ access target bucket ได้</li></ol><p><img src="`+t+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>Copy <code>Access Key ID</code> และ <code>Secret Access Key</code> ที่สร้างขึ้น</li></ol><p><img src="'+a+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>กลับไปหน้า R2 bucket และ confirm bucket name</li><li>จด S3 API endpoint ของ account โดยปกติหน้าตาแบบนี้:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="ขั้นตอนตั้งค่า" tabindex="-1">ขั้นตอนตั้งค่า <a class="header-anchor" href="#ขั้นตอนตั้งค่า" aria-label="Permalink to &quot;ขั้นตอนตั้งค่า&quot;">​</a></h2><ol><li>เปิด Upload Settings</li><li>คลิก Add Channel</li><li>เลือก <code>S3</code></li><li>ใส่ channel name ที่จำได้ เช่น <code>s3test</code></li><li>ใส่ S3 API endpoint ใน <code>Endpoint</code></li><li>ถ้าใช้ custom CDN ให้ใส่ใน <code>Custom CDN domain</code>; ถ้าไม่ใช้ให้เว้นว่าง</li><li>ใส่ bucket name</li><li>ใส่ region สำหรับตัวอย่าง Cloudflare R2 ใช้ <code>auto</code></li><li>ใส่ Access Key ID และ Secret Access Key</li><li>ปล่อย path-style access เป็น off เว้นแต่ provider ระบุชัดว่าต้องใช้</li><li>ถ้าต้องการ capacity control ให้เปิด quota limit แล้วใส่ capacity limit และ threshold</li><li>คลิก Save</li></ol><p><img src="'+d+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="วิธีตรวจสอบ" tabindex="-1">วิธีตรวจสอบ <a class="header-anchor" href="#วิธีตรวจสอบ" aria-label="Permalink to &quot;วิธีตรวจสอบ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>วิธีตรวจสอบ</th></tr></thead><tbody><tr><td>เห็น channel card</td><td>หลัง save หน้า Upload Settings ควรแสดง S3 channel card</td></tr><tr><td>Channel enabled</td><td>Switch มุมขวาบนของ card ควรอยู่ on</td></tr><tr><td>Key fields ถูกบันทึก</td><td>Detail view ควรแสดง Endpoint, Bucket, Region, path-style access และ fields ที่เกี่ยวข้อง</td></tr><tr><td>Upload ใช้งานได้</td><td>Upload test image แล้วตรวจว่า object ไปอยู่ใน target bucket</td></tr><tr><td>Link เปิดได้</td><td>Image link ที่ได้หลัง upload ควรเปิดได้ปกติ</td></tr><tr><td>Capacity display ใช้งานได้</td><td>ถ้าเปิด quota limit card ควรแสดง used capacity และ configured limit</td></tr></tbody></table><p>S3 capacity statistics คำนวณจาก local file records ของ ImgBed ไม่ได้ query provider bucket แบบ real time หลัง save S3 configuration แล้ว system จะ recalculate quota ledger จาก current D1 records</p><p><img src="'+s+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ควรเปิด-path-style-access-ไหม" tabindex="-1">ควรเปิด path-style access ไหม? <a class="header-anchor" href="#ควรเปิด-path-style-access-ไหม" aria-label="Permalink to &quot;ควรเปิด path-style access ไหม?&quot;">​</a></h3><p>โดยทั่วไปไม่ต้อง</p><p>เปิดเฉพาะเมื่อ S3-compatible provider ไม่รองรับ virtual-hosted-style URLs หรือ provider documentation ระบุชัดว่าต้องใช้ path-style access บาง MinIO, self-hosted S3 และ OpenList-compatible endpoints อาจต้องใช้</p><h3 id="cdn-domain-ใช้ทําอะไร" tabindex="-1">CDN domain ใช้ทำอะไร? <a class="header-anchor" href="#cdn-domain-ใช้ทําอะไร" aria-label="Permalink to &quot;CDN domain ใช้ทำอะไร?&quot;">​</a></h3><p>ถ้าคุณวาง CDN หรือ custom access domain ไว้หน้า bucket ให้ใส่ตรงนี้</p><p>หลัง configure แล้ว generated file links จะ prefer domain นี้ ถ้าไม่ได้ใช้ CDN ให้เว้นว่าง</p><h3 id="upload-fail-เพราะอะไร" tabindex="-1">Upload fail เพราะอะไร? <a class="header-anchor" href="#upload-fail-เพราะอะไร" aria-label="Permalink to &quot;Upload fail เพราะอะไร?&quot;">​</a></h3><p>ตรวจสิ่งเหล่านี้ก่อน:</p><ol><li>Endpoint เป็น full <code>https://</code> URL</li><li>Bucket name ถูกต้อง</li><li>Region ตรงกับ requirement ของ provider</li><li>Copy Access Key ID และ Secret Access Key มาครบ</li><li>Key มี write permission สำหรับ target bucket</li><li>Provider ไม่ต้องใช้ path-style access หรือถ้าต้องใช้ก็เปิดไว้แล้ว</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>เตรียม S3 Endpoint, Bucket, Region, Access Key และ Secret Key</span></span>
<span class="line"><span>-&gt; เปิด Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; เลือก S3</span></span>
<span class="line"><span>-&gt; ใส่ Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; ใส่ CDN domain หากจำเป็น</span></span>
<span class="line"><span>-&gt; ปล่อย path-style access off เป็นค่าเริ่มต้น</span></span>
<span class="line"><span>-&gt; เปิด quota limit หากจำเป็น</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Upload test image แล้วตรวจผล</span></span></code></pre></div>`,40)])])}const k=l(c,[["render",r]]);export{f as __pageData,k as default};
